    pid_t pid;

    // Create a pipe
    if (pipe(pipefd) == -1) {
        std::cerr << "Pipe failed" << std::endl;
        return 1;
    }

    // Fork a new process
    pid = fork();
    if (pid < 0) { // Fork failed
        std::cerr << "Fork failed" << std::endl;
        return 1;
    }

    if (pid > 0) { // Parent process
        // Close the writing end of the pipe
        close(pipefd[1]);

        // Read from the pipe
